const chartColors={primary:'#6366f1',secondary:'#8b5cf6',success:'#00A86B',warning:'#FFD700',danger:'#ef4444',info:'#3b82f6',gradient1:['rgba(99, 102, 241, 0.8)','rgba(99, 102, 241, 0.1)'],gradient2:['rgba(139, 92, 246, 0.8)','rgba(139, 92, 246, 0.1)']};function createGradient(ctx,color1,color2){const gradient=ctx.createLinearGradient(0,0,0,400);gradient.addColorStop(0,color1);gradient.addColorStop(1,color2);return gradient;}
const defaultOptions={responsive:true,maintainAspectRatio:false,plugins:{legend:{display:true,position:'top',labels:{color:'rgba(255, 255, 255, 0.8)',font:{size:12,family:"'Inter', sans-serif"},padding:15,usePointStyle:true}},tooltip:{backgroundColor:'rgba(15, 15, 35, 0.95)',titleColor:'#fff',bodyColor:'rgba(255, 255, 255, 0.8)',borderColor:'rgba(99, 102, 241, 0.3)',borderWidth:1,padding:12,cornerRadius:8,displayColors:true,callbacks:{label:function(context){let label=context.dataset.label||'';if(label)label+=': ';if(context.parsed.y!==null){label+=new Intl.NumberFormat('en-US',{style:'currency',currency:'USD'}).format(context.parsed.y);}
return label;}}}},scales:{x:{grid:{color:'rgba(255, 255, 255, 0.05)',drawBorder:false},ticks:{color:'rgba(255, 255, 255, 0.6)',font:{size:11}}},y:{grid:{color:'rgba(255, 255, 255, 0.05)',drawBorder:false},ticks:{color:'rgba(255, 255, 255, 0.6)',font:{size:11},callback:function(value){return'$'+value.toLocaleString();}}}}};function initPortfolioChart(canvasId,data){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');const gradient=createGradient(ctx,chartColors.gradient1[0],chartColors.gradient1[1]);return new Chart(ctx,{type:'line',data:{labels:data.labels||['Jan','Feb','Mar','Apr','May','Jun','Jul'],datasets:[{label:'Portfolio Value',data:data.values||[10000,12500,15000,18000,22000,25000,30000],fill:true,backgroundColor:gradient,borderColor:chartColors.primary,borderWidth:2,tension:0.4,pointRadius:4,pointBackgroundColor:chartColors.primary,pointBorderColor:'#fff',pointBorderWidth:2,pointHoverRadius:6}]},options:{...defaultOptions,plugins:{...defaultOptions.plugins,title:{display:true,text:'Portfolio Growth',color:'rgba(255, 255, 255, 0.9)',font:{size:16,weight:'600'},padding:{bottom:20}}}}});}
function initDistributionChart(canvasId,data){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');return new Chart(ctx,{type:'doughnut',data:{labels:data.labels||['Bitcoin','Ethereum','Forex','Stocks','Real Estate'],datasets:[{data:data.values||[35,25,20,12,8],backgroundColor:[chartColors.primary,chartColors.secondary,chartColors.success,chartColors.warning,chartColors.info],borderColor:'rgba(15, 15, 35, 0.8)',borderWidth:3,hoverOffset:8}]},options:{responsive:true,maintainAspectRatio:false,cutout:'65%',plugins:{legend:{position:'right',labels:{color:'rgba(255, 255, 255, 0.8)',font:{size:12},padding:15,usePointStyle:true,pointStyle:'circle'}},tooltip:{...defaultOptions.plugins.tooltip,callbacks:{label:function(context){return context.label+': '+context.parsed+'%';}}},title:{display:true,text:'Investment Distribution',color:'rgba(255, 255, 255, 0.9)',font:{size:16,weight:'600'},padding:{bottom:20}}}}});}
function initEarningsChart(canvasId,data){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');return new Chart(ctx,{type:'bar',data:{labels:data.labels||['Jan','Feb','Mar','Apr','May','Jun'],datasets:[{label:'Earnings',data:data.values||[1200,1500,1800,2200,2800,3500],backgroundColor:chartColors.primary,borderRadius:8,barThickness:30,hoverBackgroundColor:chartColors.secondary}]},options:{...defaultOptions,plugins:{...defaultOptions.plugins,title:{display:true,text:'Monthly Earnings',color:'rgba(255, 255, 255, 0.9)',font:{size:16,weight:'600'},padding:{bottom:20}}}}});}
function initAdminStatsChart(canvasId,data){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');return new Chart(ctx,{type:'line',data:{labels:data.labels||['Week 1','Week 2','Week 3','Week 4'],datasets:[{label:'Deposits',data:data.deposits||[50000,75000,62000,90000],borderColor:chartColors.success,backgroundColor:'transparent',borderWidth:2,tension:0.4,pointRadius:4,pointBackgroundColor:chartColors.success},{label:'Withdrawals',data:data.withdrawals||[20000,35000,28000,45000],borderColor:chartColors.danger,backgroundColor:'transparent',borderWidth:2,tension:0.4,pointRadius:4,pointBackgroundColor:chartColors.danger},{label:'Investments',data:data.investments||[45000,60000,55000,80000],borderColor:chartColors.primary,backgroundColor:'transparent',borderWidth:2,tension:0.4,pointRadius:4,pointBackgroundColor:chartColors.primary}]},options:{...defaultOptions,plugins:{...defaultOptions.plugins,title:{display:true,text:'Platform Activity',color:'rgba(255, 255, 255, 0.9)',font:{size:16,weight:'600'},padding:{bottom:20}}}}});}
function initUserGrowthChart(canvasId,data){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');const gradient=createGradient(ctx,chartColors.gradient2[0],chartColors.gradient2[1]);return new Chart(ctx,{type:'line',data:{labels:data.labels||['Jan','Feb','Mar','Apr','May','Jun'],datasets:[{label:'Total Users',data:data.values||[100,250,450,800,1200,1800],fill:true,backgroundColor:gradient,borderColor:chartColors.secondary,borderWidth:2,tension:0.4,pointRadius:4,pointBackgroundColor:chartColors.secondary}]},options:{...defaultOptions,scales:{...defaultOptions.scales,y:{...defaultOptions.scales.y,ticks:{...defaultOptions.scales.y.ticks,callback:function(value){return value.toLocaleString();}}}},plugins:{...defaultOptions.plugins,tooltip:{...defaultOptions.plugins.tooltip,callbacks:{label:function(context){return'Users: '+context.parsed.y.toLocaleString();}}},title:{display:true,text:'User Growth',color:'rgba(255, 255, 255, 0.9)',font:{size:16,weight:'600'},padding:{bottom:20}}}}});}
async function initDashboardCharts(){try{const[portfolioRes,distributionRes,earningsRes]=await Promise.all([fetchWithAuth(`${DASHBOARD_API}/api/stats/chart/portfolio`).catch(()=>null),fetchWithAuth(`${DASHBOARD_API}/api/stats/chart/distribution`).catch(()=>null),fetchWithAuth(`${DASHBOARD_API}/api/stats/chart/earnings`).catch(()=>null)]);if(portfolioRes?.ok){const data=await portfolioRes.json();if(data.success&&data.data){initPortfolioChart('portfolioChart',data.data);}}else{initPortfolioChart('portfolioChart',{labels:[],values:[]});}
if(distributionRes?.ok){const data=await distributionRes.json();if(data.success&&data.data){initDistributionChart('distributionChart',data.data);}}
if(earningsRes?.ok){const data=await earningsRes.json();if(data.success&&data.data){initEarningsChart('earningsChart',data.data);}}}catch(error){console.error("Failed to load chart data:",error);}}
function initAdminCharts(){const statsData={labels:['Week 1','Week 2','Week 3','Week 4'],deposits:[50000,75000,62000,90000],withdrawals:[20000,35000,28000,45000],investments:[45000,60000,55000,80000]};initAdminStatsChart('adminStatsChart',statsData);const growthData={labels:['Jan','Feb','Mar','Apr','May','Jun'],values:[100,250,450,800,1200,1800]};initUserGrowthChart('userGrowthChart',growthData);}
document.addEventListener('DOMContentLoaded',()=>{if(document.body.classList.contains('dashboard-site')){initDashboardCharts();}
if(document.body.classList.contains('admin-site')){initAdminCharts();}});function initProfitLossChart(canvasId,data){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');const values=data.values||[500,-200,800,-150,1200,300,-400,900,-100,600];const backgroundColors=values.map(v=>v>=0?chartColors.success:chartColors.danger);const borderColors=values.map(v=>v>=0?'#059669':'#dc2626');return new Chart(ctx,{type:'bar',data:{labels:data.labels||['Day 1','Day 2','Day 3','Day 4','Day 5','Day 6','Day 7','Day 8','Day 9','Day 10'],datasets:[{label:'Daily P&L',data:values,backgroundColor:backgroundColors,borderColor:borderColors,borderWidth:1,borderRadius:4,barThickness:20}]},options:{...defaultOptions,plugins:{...defaultOptions.plugins,title:{display:true,text:'Daily Profit & Loss',color:'rgba(255, 255, 255, 0.9)',font:{size:16,weight:'600'},padding:{bottom:20}},tooltip:{...defaultOptions.plugins.tooltip,callbacks:{label:function(context){const value=context.parsed.y;const prefix=value>=0?'+':'';return`P&L:${prefix}$${value.toLocaleString()}`;},labelColor:function(context){const value=context.parsed.y;return{backgroundColor:value>=0?chartColors.success:chartColors.danger,borderColor:value>=0?'#059669':'#dc2626'};}}}},scales:{...defaultOptions.scales,y:{...defaultOptions.scales.y,grid:{color:function(context){if(context.tick.value===0){return'rgba(255, 255, 255, 0.3)';}
return'rgba(255, 255, 255, 0.05)';},lineWidth:function(context){return context.tick.value===0?2:1;}},ticks:{...defaultOptions.scales.y.ticks,callback:function(value){const prefix=value>=0?'+':'';return prefix+'$'+value.toLocaleString();}}}}}});}
function initScrollingTickerChart(canvasId,options={}){const canvas=document.getElementById(canvasId);if(!canvas)return null;const ctx=canvas.getContext('2d');const maxDataPoints=options.maxDataPoints||20;const labels=[];const profitData=[];const lossData=[];for(let i=0;i<maxDataPoints;i++){labels.push(`T-${maxDataPoints-i}`);const value=(Math.random()-0.4)*1000;if(value>=0){profitData.push(value);lossData.push(0);}else{profitData.push(0);lossData.push(Math.abs(value));}}
const chart=new Chart(ctx,{type:'bar',data:{labels:labels,datasets:[{label:'Profit',data:profitData,backgroundColor:'rgba(16, 185, 129, 0.8)',borderColor:'#059669',borderWidth:1,borderRadius:2,barPercentage:0.8},{label:'Loss',data:lossData.map(v=>-v),backgroundColor:'rgba(239, 68, 68, 0.8)',borderColor:'#dc2626',borderWidth:1,borderRadius:2,barPercentage:0.8}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:300},plugins:{legend:{display:true,position:'top',labels:{color:'rgba(255, 255, 255, 0.8)',font:{size:11},usePointStyle:true}},title:{display:true,text:'Live Trading Activity',color:'rgba(255, 255, 255, 0.9)',font:{size:14,weight:'600'}}},scales:{x:{stacked:true,grid:{display:false},ticks:{display:false}},y:{stacked:true,grid:{color:'rgba(255, 255, 255, 0.05)',drawBorder:false},ticks:{color:'rgba(255, 255, 255, 0.6)',font:{size:10},callback:function(value){return(value>=0?'+':'')+'$'+value.toFixed(0);}}}}}});if(options.autoUpdate!==false){setInterval(()=>{chart.data.labels.shift();chart.data.datasets[0].data.shift();chart.data.datasets[1].data.shift();chart.data.labels.push('Now');const newValue=(Math.random()-0.4)*1000;if(newValue>=0){chart.data.datasets[0].data.push(newValue);chart.data.datasets[1].data.push(0);}else{chart.data.datasets[0].data.push(0);chart.data.datasets[1].data.push(newValue);}
chart.update('none');},options.updateInterval||2000);}
return chart;}
window.ChartUtils={initPortfolioChart,initDistributionChart,initEarningsChart,initAdminStatsChart,initUserGrowthChart,initProfitLossChart,initScrollingTickerChart,chartColors,createGradient};